import React from "react";

function MigrantSpecification() {

  const services = [
    {
      title: "🏘 Housing & Rent Guidance",
      desc: "Information about affordable rental houses, PG accommodation and temporary shelters in Dombivli West area."
    },
    {
      title: "🗺 Nearby Essentials",
      desc: "Find nearby ration shops, hospitals, police stations, markets, banks and government offices."
    },
    {
      title: "📄 Ration Card Assistance",
      desc: "Help for applying new ration card, updating address and linking Aadhaar with ration services."
    },
    {
      title: "🏥 Health Scheme Support",
      desc: "Ayushman Bharat, Mahatma Jyotiba Phule Health Scheme and local KDMC health programs."
    },
    {
      title: "🛡 Insurance Awareness",
      desc: "Information on PM Jeevan Jyoti Bima Yojana, Suraksha Bima Yojana and health insurance enrollment."
    },
    {
      title: "🎉 Local Festivals & Events",
      desc: "Updates about Dombivli West local festivals, cultural programs and community activities."
    },
    {
      title: "🏢 Government Help Centers",
      desc: "Details of KDMC citizen facilitation centers and migrant support offices."
    },
    {
      title: "📍 Area Orientation Guide",
      desc: "Basic orientation about Dombivli West zones, bus routes, railway connectivity and public services."
    }
  ];

  return (
    <div style={styles.container}>

      <h2 style={styles.heading}>
        🌍 Migrant Citizen Support Hub — Dombivli West
      </h2>

      <p style={styles.subtitle}>
        Dedicated support system for migrant workers and families to help them
        settle, access government schemes and essential services.
      </p>

      <div style={styles.grid}>

        {services.map((item, index) => (
          <div key={index} style={styles.card}>
            <h3>{item.title}</h3>
            <p>{item.desc}</p>
          </div>
        ))}

      </div>

    </div>
  );
}

/* STYLES */

const styles = {

  container: {
    padding: "10px",
  },

  heading: {
    textAlign: "center",
    marginBottom: "10px",
    color: "#ffb347"
  },

  subtitle: {
    textAlign: "center",
    maxWidth: "800px",
    margin: "0 auto 25px",
    lineHeight: "1.6"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: "18px"
  },

  card: {
    background: "rgba(255,255,255,0.08)",
    padding: "18px",
    borderRadius: "15px",
    backdropFilter: "blur(10px)",
    boxShadow: "0 8px 20px rgba(0,0,0,0.4)",
    transition: "0.3s",
    cursor: "pointer"
  }

};

export default MigrantSpecification;
